props.extensibilityCode:
// ToggleGroup type=multiple com analytics
const [formats, setFormats] = useState<string[]>([]);

<ToggleGroup
  type="multiple"
  value={formats}
  onValueChange={(next) => {
    track('field_change', {
      component: 'toggle_group',
      field_name: 'text_formatting',
      value: next.join(','),
    });
    setFormats(next);
  }}
  aria-label="Formatação"
>
  <ToggleGroupItem value="bold" aria-label="Negrito">
    <Bold aria-hidden="true" />
  </ToggleGroupItem>
  <ToggleGroupItem value="italic" aria-label="Itálico">
    <Italic aria-hidden="true" />
  </ToggleGroupItem>
  <ToggleGroupItem value="underline" aria-label="Sublinhado">
    <Underline aria-hidden="true" />
  </ToggleGroupItem>
</ToggleGroup>

tokens.customizationCode:
/* Spacing customizado entre itens */
[data-slot="toggle-group"] {
  --gap: 2;
}

/* Cor customizada do estado selecionado */
.toggle-group-brand [data-state="on"] {
  @apply bg-blue-500 text-white;
}

